const { exec } = require('child_process');
const util = require('util');
const execPromise = util.promisify(exec);

/**
 * Resizes an image and applies special effects using ImageMagick/GraphicsMagick.
 *
 * @param {string} inputFilename - The path to the input image file.
 * @param {string} outputFilename - The path for the output image file.
 * @param {string} dimensions - The desired dimensions (e.g., '200x200', '100%', '200x').
 * @param {string[]} [effects=[]] - An array of special effects to apply.
 *                                  Supported effects: 'grayscale', 'sepia', 'blur', 'enhance'.
 * @returns {Promise<object>} A promise that resolves with success message or rejects with an error.
 *
 * @example
 * // Resize and apply grayscale and enhance
 * resizeImage('user_photo.jpg', 'thumb_gray_enhanced.jpg', '200x200', ['grayscale', 'enhance'])
 *   .then(result => console.log(result.message))
 *   .catch(error => console.error(error.message));
 *
 * @example
 * // Basic resize
 * resizeImage('input.png', 'output.webp', '500x500')
 *   .then(result => console.log(result.message))
 *   .catch(error => console.error(error.message));
 */
async function resizeImage(inputFilename, outputFilename, dimensions, effects = []) {
    let commandParts = ['convert', inputFilename]; // 'convert' command typically refers to ImageMagick

    // Add resize option
    commandParts.push('-resize', dimensions);

    // Apply special effects based on the 'effects' array
    if (effects.includes('grayscale')) {
        commandParts.push('-colorspace', 'Gray');
    }
    if (effects.includes('sepia')) {
        commandParts.push('-sepia-tone', '80%'); // 80% is a common sepia tone value
    }
    if (effects.includes('blur')) {
        commandParts.push('-blur', '0x2'); // A common light blur (radius x sigma)
    }
    if (effects.includes('enhance')) {
        commandParts.push('-enhance');
    }

    // Add the output filename
    commandParts.push(outputFilename);

    const command = commandParts.join(' ');

    try {
        const { stdout, stderr } = await execPromise(command);

        if (stderr) {
            console.warn('ImageMagick/GraphicsMagick stderr:', stderr);
        }
        console.log('ImageMagick/GraphicsMagick stdout:', stdout);

        return { success: true, message: `Image processed successfully: ${outputFilename}` };
    } catch (error) {
        console.error('Error processing image:', error);
        throw new Error(`Failed to process image: ${error.message}`);
    }
}

module.exports = resizeImage;